def compute_flags(word: str, pos: str) -> dict:
    """Automatically compute boolean flags from word and part-of-speech."""
    w = word.lower()
    p = pos.lower()
    is_verb = "verb" in p or p == "verb"
    return {
        "is_question_word":       w in QUESTION_WORDS,
        "is_action_word":         is_verb and w not in AUXILIARY_VERBS,
        "is_object_word":         w in OBJECT_NOUNS,
        "is_connector_word":      w in CONJUNCTIONS or w in PREPOSITIONS,
        "is_pronoun":             w in PRONOUNS,
        "is_preposition":         w in PREPOSITIONS,
        "is_emotion_word":        w in EMOTION_WORDS,
        "is_time_word":           w in TIME_WORDS,
        "is_place_word":          w in PLACE_WORDS,
        "is_common_daily_word":   w in COMMON_DAILY,
        "is_auxiliary_verb":      w in AUXILIARY_VERBS,
        "is_negation_word":       w in NEGATION_WORDS,
        "is_numeric_word":        w in NUMERIC_WORDS,
        "is_logic_operator":      w in LOGIC_OPERATORS,
        "is_command_word":        is_verb and p in ("verb","auxiliary verb") and w in {"go","stop","come","look","sit","stand","run","walk","read","write","speak","listen","wait","help","take","give","make","use","put","set","call","tell","show","keep","hold","turn","open","close","start","find","ask","try","learn","teach","move","stay","leave","bring","send","let","get","do","say","watch","play","eat","drink","build","drive","follow","push","pull","raise","drop","cut","carry","beat","beat"},
        "is_identity_word":       w in IDENTITY_WORDS,
        "is_learning_trigger_word": w in LEARNING_TRIGGERS,
    }

def expand(raw: dict) -> dict:
    """Convert compact raw entry to full schema dict."""
    word = raw["w"]
    pos  = raw.get("pos", "")
    flags = compute_flags(word, pos)
    return {
        "word":                    word,
        "lowercase":               word.lower(),
        "letters":                 list(word),
        "syllables":               raw.get("syl", [word.lower()]),
        "phonetic":                raw.get("ph", ""),
        "part_of_speech":          pos,
        "grammar_role":            raw.get("gr", ""),
        "root_word":               raw.get("rt", word.lower()),
        "word_family":             raw.get("fam", []),
        "plural_form":             raw.get("pl", ""),
        "tense_forms":             raw.get("tn", []),
        "hindi_meaning":           raw.get("hi", ""),
        "english_meaning":         raw.get("en", ""),
        "definition_simple":       raw.get("ds", ""),
        "definition_detailed":     raw.get("dd", ""),
        "example_sentence":        raw.get("ex", ""),
        "example_sentence_hindi":  raw.get("exh", ""),
        "sentence_usage_roles":    raw.get("su", []),
        "word_usage_context":      raw.get("wuc", []),
        **flags,
        "synonyms":                raw.get("syn", []),
        "antonyms":                raw.get("ant", []),
        "related_words":           raw.get("rel", []),
        "contextual_variations":   raw.get("cv", []),
        "semantic_tags":           raw.get("st", []),
        "difficulty_level":        raw.get("dif", "basic"),
        "frequency_rank":          raw.get("fr", 9999),
        "emotion_weight":          raw.get("ew", 0.0),
        "intent_type":             raw.get("it", "informational"),
        "response_priority":       raw.get("rp", "medium"),
        "conversation_stage":      raw.get("cs", "any"),
        "dialogue_category":       raw.get("dc", "statement"),
        "topic_domain":            raw.get("td", "general"),
        "sentence_position_role":  raw.get("spr", "any"),
        "dependency_links":        raw.get("dl", []),
        "co_occurrence_words":     raw.get("co", []),
    }

