# ---------------------------------------------------------------------------
# MAIN — expand all entries and write JSON output files
# ---------------------------------------------------------------------------

def main():
    entries = [expand(r) for r in WORDS_RAW]

    # Remove duplicate words (keep first occurrence by frequency_rank)
    seen = {}
    unique_entries = []
    for e in entries:
        w = e["lowercase"]
        if w not in seen:
            seen[w] = True
            unique_entries.append(e)

    # Write batch file (all current words in one batch)
    batch_path = os.path.join(OUTPUT_DIR, "dictionary_batch_001.json")
    with open(batch_path, "w", encoding="utf-8") as f:
        json.dump(unique_entries, f, ensure_ascii=False, indent=2)
    print(f"Written {len(unique_entries)} entries -> {batch_path}")

    # Write index: word -> frequency_rank
    index = {e["lowercase"]: e["frequency_rank"] for e in unique_entries}
    index_path = os.path.join(OUTPUT_DIR, "index.json")
    with open(index_path, "w", encoding="utf-8") as f:
        json.dump(index, f, ensure_ascii=False, indent=2)
    print(f"Written {len(index)} entries -> {index_path}")


if __name__ == "__main__":
    main()
